INSERT INTO public.mst_mb_head (
  mbh_oracle_sys_id, mbh_mb_costing, mbh_mgt_name,
  mbh_denier, mbh_filament, mbh_dozing,
  mbh_orion_item_code, mbh_mb_spg_orion, mbh_run_ldr_pct,
  mbh_d_f, mbh_lesture, mbh_vs_number,
  mbh_check_status, mbh_status, mbh_ldr_prsn, mbh_final_product, mbh_code,
  mbh_is_active, notes, created_by, created_at, updated_by, updated_at
)
SELECT
  s.oracle_sys_id, s.mb_costing, s.mgt_name,
  s.denier, s.filament, s.dozing,
  s.orion_item_code, s.mb_spg_orion, s.run_ldr_pct,
  s.d_f, s.lesture, s.vs_number,
  NULLIF(s.check_status, ''), NULLIF(s.mbh_status, ''),
  s.ldr_prsn, NULLIF(s.final_product, ''), NULLIF(s.code, ''),
  s.is_active, NULLIF(s.notes, ''),
  COALESCE(NULLIF(s.created_by, ''), 'oracle_csv'),
  COALESCE(s.created_at, NOW()),
  NULLIF(s.updated_by, ''),
  s.updated_at
FROM _stg_mb_head_csv s
ON CONFLICT DO NOTHING;

